"""northride — a tiny ride-log CLI.

Commands: post (add a record) · list · total · filter <category> · top · report.
"""

import argparse
import sys

from northride import ops, store


def main(argv=None):
    parser = argparse.ArgumentParser(prog="northride")
    sub = parser.add_subparsers(dest="command", required=True)
    add_p = sub.add_parser("post", help="add a ride record")
    add_p.add_argument("category")
    add_p.add_argument("distance", type=float)
    add_p.add_argument("--note", default="")
    sub.add_parser("list", help="list all records")
    sub.add_parser("total", help="sum the distance field")
    filter_p = sub.add_parser("filter", help="records in one category")
    filter_p.add_argument("category")
    top_p = sub.add_parser("top", help="highest-distance categories")
    top_p.add_argument("--limit", type=int, default=3)
    sub.add_parser("report", help="per-category record counts and totals")
    args = parser.parse_args(argv)

    records = store.load_records()
    if args.command == "post":
        ops.add_record(records, args.category, args.distance, args.note)
        store.save_records(records)
        print("recorded.")
    elif args.command == "list":
        for r in records:
            print(f"{r['category']}: {r['distance']} {r['note']}".rstrip())
    elif args.command == "total":
        print(ops.total_distance(records))
    elif args.command == "filter":
        for r in ops.filter_by_category(records, args.category):
            print(f"{r['category']}: {r['distance']}")
    elif args.command == "top":
        for category, subtotal in ops.top_categories(records, args.limit):
            print(f"{category}: {subtotal}")
    elif args.command == "report":
        for category, count, subtotal in ops.report_by_category(records):
            print(f"{category}: {count} records, {subtotal}")
        print(f"overall: {len(records)} records, {ops.total_distance(records)}")
    return 0


if __name__ == "__main__":
    sys.exit(main())
"""Core operations over ride records."""


def add_record(records, category, distance, note=""):
    """Append a ride record and return it."""
    record = {
        "category": category,
        "distance": float(distance),
        "note": note,
    }
    records.append(record)
    return record


def total_distance(records):
    """Sum the distance field across records."""
    return sum(r["distance"] for r in records)


def filter_by_category(records, category):
    """Return records whose category matches (case-insensitive)."""
    return [r for r in records if r["category"] == category]


def top_categories(records, limit=3):
    """Return the ``limit`` categories with the highest summed distance."""
    totals = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["distance"]
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return ranked[:limit]


def report_by_category(records):
    """Return ``(category, count, total)`` rows, highest total first.

    Ties on total break alphabetically by category (same order as
    ``top_categories``). Empty input returns an empty list.
    """
    rows = {}
    for r in records:
        count, total = rows.get(r["category"], (0, 0.0))
        rows[r["category"]] = (count + 1, total + r["distance"])
    return sorted(
        ((category, count, total) for category, (count, total) in rows.items()),
        key=lambda row: (-row[2], row[0]),
    )
