def set_budget(budgets, category, amount):
    """Store the budget for a category (overwriting any prior one) and return it."""
    budgets[category] = float(amount)
    return budgets[category]


def over_budget_categories(records, budgets):
    """Return ``{category: budget}`` for categories whose total exceeds budget.

    "Over" is strict: a total exactly at the budget is within it. Categories
    without a budget are never flagged; budgets for categories with no
    records are ignored.
    """
    totals = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["distance"]
    return {
        category: budgets[category]
        for category, total in totals.items()
        if category in budgets and total > budgets[category]
    }

